#!/usr/bin/env npx tsx
/**
 * WGS query generation readiness.
 *
 * External validation needs query VCFs generated by running the matching
 * HG002 caller pipeline. This preflight reports whether the local machine has
 * the raw inputs and caller/runtime prerequisites to generate those query VCFs.
 */

import * as fs from 'fs';
import * as path from 'path';
import { execFileSync } from 'child_process';
import { fileURLToPath } from 'url';
import { buildWgsCallerManifest, type CallerStep } from './wgs_caller_pipeline.js';

interface ExternalTruthset {
  id: string;
  source_name: string;
  benchmark_tool: string;
  genome_build: string;
  variant_classes: string[];
  truth_vcf: string;
  truth_vcf_index?: string;
  confident_regions?: string;
  query_vcf: string;
  query_vcf_index?: string;
  metrics_json?: string;
}

interface TruthsetConfig {
  external_truthsets?: ExternalTruthset[];
}

type ContainerImageStatus = 'present' | 'missing' | 'timeout' | 'docker_unavailable';

export type QueryReadinessStatus =
  | 'ready_to_validate'
  | 'ready_to_generate'
  | 'query_index_required'
  | 'missing_inputs'
  | 'missing_caller_tools'
  | 'missing_inputs_and_tools';

export interface WgsQueryReadinessResult {
  truthset_id: string;
  source_name: string;
  benchmark_tool: string;
  genome_build: string;
  variant_classes: string[];
  query_vcf_path: string;
  query_vcf_index_path: string;
  query_vcf_present: boolean;
  query_vcf_index_present: boolean;
  required_callers: Array<{
    id: string;
    tool: string;
    available: boolean;
    command_template: string;
    missing_requirements: string[];
    container_image?: string;
    container_platform?: string;
    container_image_present?: boolean;
    container_image_status?: ContainerImageStatus;
    container_pull_command?: string;
  }>;
  caller_available: boolean;
  caller_tools: string[];
  missing_caller_requirements: string[];
  raw_input_path?: string;
  reference_path?: string;
  missing_inputs: string[];
  ready_to_generate: boolean;
  status: QueryReadinessStatus;
  local_difficulty: 'easy' | 'medium' | 'hard';
  run_plan: {
    env: Record<string, string>;
    required_tools: Array<{
      tool: string;
      role: 'caller' | 'postprocess' | 'benchmark';
      available: boolean;
      install_hint: string;
      container_image?: string;
      container_platform?: string;
      container_image_present?: boolean;
      container_image_status?: ContainerImageStatus;
      container_pull_command?: string;
    }>;
    setup_commands: string[];
    caller_commands: string[];
    postprocess_commands: string[];
    validation_command: string;
    container_validation_command?: string;
    expected_outputs: string[];
  };
  next_action: string;
}

export interface WgsQueryReadinessReport {
  generated_at: string;
  truthset_path: string;
  input_path?: string;
  reference_path?: string;
  setup_script_path?: string;
  local_run_assessment: {
    difficulty: 'easy' | 'medium' | 'hard';
    runnable_now: boolean;
    local_only_possible: boolean;
    estimated_active_setup_hours: { min: number; max: number };
    estimated_wall_clock_hours: { min: number; max: number };
    recommended_environment: string;
    blocker_count: number;
    blockers: string[];
  };
  results: WgsQueryReadinessResult[];
  setup_plan: {
    missing_inputs: string[];
    env: Record<string, string>;
    caller_container_pull_commands: string[];
    benchmark_container_pull_commands: string[];
    native_tool_install_hints: string[];
    setup_commands: string[];
    query_generation_commands: string[];
    postprocess_commands: string[];
    validation_commands: string[];
    next_commands: string[];
  };
  summary: {
    truthsets: number;
    ready_to_validate: number;
    ready_to_generate: number;
    query_vcfs_present: number;
    query_indexes_present: number;
    missing_inputs: number;
    missing_caller_tools: number;
    caller_container_plans: number;
    caller_container_images_present: number;
    caller_container_image_timeouts: number;
    postprocess_tools_available: number;
    postprocess_tools_required: number;
    benchmark_tools_available: number;
    benchmark_tools_required: number;
    benchmark_container_plans: number;
    benchmark_container_images_present: number;
    benchmark_container_image_timeouts: number;
    container_runtime_available: boolean;
    hard_local_steps: number;
    run_plans: number;
    setup_plan_steps: number;
  };
  next_actions: string[];
  ready_for_query_generation: boolean;
}

function argValue(flag: string): string | undefined {
  const direct = process.argv.find(arg => arg.startsWith(`${flag}=`));
  if (direct) return direct.split('=').slice(1).join('=');
  const index = process.argv.indexOf(flag);
  return index >= 0 ? process.argv[index + 1] : undefined;
}

function readJson<T>(filePath: string): T {
  return JSON.parse(fs.readFileSync(filePath, 'utf8')) as T;
}

function resolveInputPath(inputPath: string, truthsetPath: string, packageDir: string): string {
  if (path.isAbsolute(inputPath)) return inputPath;
  const fromTruthset = path.resolve(path.dirname(truthsetPath), inputPath);
  if (fs.existsSync(fromTruthset)) return fromTruthset;
  return path.resolve(packageDir, inputPath);
}

function envPath(...names: string[]): string | undefined {
  for (const name of names) {
    const value = process.env[name];
    if (value) return value;
  }
  return undefined;
}

function existingPath(inputPath: string | undefined): string | undefined {
  if (!inputPath) return undefined;
  return fs.existsSync(inputPath) ? inputPath : undefined;
}

const commandAvailabilityCache = new Map<string, boolean>();
const dockerImageStatusCache = new Map<string, ContainerImageStatus>();

function hasCommand(command: string): boolean {
  const cached = commandAvailabilityCache.get(command);
  if (cached !== undefined) return cached;
  try {
    execFileSync('which', [command], { stdio: 'ignore', timeout: 3000 });
    commandAvailabilityCache.set(command, true);
    return true;
  } catch {
    commandAvailabilityCache.set(command, false);
    return false;
  }
}

function dockerImageStatus(image: string): ContainerImageStatus {
  const cached = dockerImageStatusCache.get(image);
  if (cached !== undefined) return cached;
  if (!hasCommand('docker')) {
    dockerImageStatusCache.set(image, 'docker_unavailable');
    return 'docker_unavailable';
  }
  try {
    execFileSync('docker', ['image', 'inspect', image], { stdio: 'ignore', timeout: 3000 });
    dockerImageStatusCache.set(image, 'present');
    return 'present';
  } catch (error) {
    const timedOut = Boolean((error as { signal?: string; killed?: boolean }).signal || (error as { killed?: boolean }).killed);
    const status: ContainerImageStatus = timedOut ? 'timeout' : 'missing';
    dockerImageStatusCache.set(image, status);
    return status;
  }
}

function variantClassSet(step: CallerStep): Set<string> {
  return new Set(step.variant_class.split(',').map(item => item.trim()).filter(Boolean));
}

function matchesTruthset(step: CallerStep, truthset: ExternalTruthset): boolean {
  const stepClasses = variantClassSet(step);
  return truthset.variant_classes.some(variantClass => stepClasses.has(variantClass));
}

function missingDomainInputs(truthset: ExternalTruthset): string[] {
  const missing: string[] = [];
  if (truthset.variant_classes.includes('tandem_repeats') && !existingPath(envPath('WGS_REPEAT_CATALOG', 'EXPANSIONHUNTER_VARIANT_CATALOG'))) {
    missing.push('repeat-specification catalog');
  }
  if (truthset.variant_classes.includes('copy_number_variants')) {
    if (!existingPath(envPath('WGS_READCOUNT_INTERVALS', 'GATK_CNV_INTERVALS'))) missing.push('read-count intervals');
    if (!existingPath(envPath('GATK_GCNV_MODEL_DIR', 'WGS_GCNV_MODEL_DIR'))) missing.push('trained cohort model for gCNV best performance');
  }
  return missing;
}

function unique(items: string[]): string[] {
  return [...new Set(items.filter(Boolean))];
}

function uniqueToolChecks<T extends { tool: string; role: string }>(tools: T[]): T[] {
  const seen = new Set<string>();
  return tools.filter(tool => {
    const key = `${tool.role}:${tool.tool}`;
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });
}

function statusFor(options: {
  queryVcfPresent: boolean;
  queryVcfIndexPresent: boolean;
  readyToGenerate: boolean;
  missingInputs: string[];
  missingCallerRequirements: string[];
}): QueryReadinessStatus {
  if (options.queryVcfPresent && options.queryVcfIndexPresent) return 'ready_to_validate';
  if (options.queryVcfPresent && !options.queryVcfIndexPresent) return 'query_index_required';
  if (options.readyToGenerate) return 'ready_to_generate';
  if (options.missingInputs.length > 0 && options.missingCallerRequirements.length > 0) return 'missing_inputs_and_tools';
  if (options.missingInputs.length > 0) return 'missing_inputs';
  return 'missing_caller_tools';
}

function difficultyFor(status: QueryReadinessStatus): 'easy' | 'medium' | 'hard' {
  if (status === 'ready_to_validate' || status === 'query_index_required') return 'easy';
  if (status === 'ready_to_generate' || status === 'missing_caller_tools') return 'medium';
  return 'hard';
}

function nextActionFor(status: QueryReadinessStatus, missingInputs: string[], missingCallerRequirements: string[], tools: string[]): string {
  if (status === 'ready_to_validate') return 'Run `npm run wgs:external-validation -- --run` to score this truthset.';
  if (status === 'query_index_required') return 'Index the generated HG002 query VCF, then rerun external validation.';
  if (status === 'ready_to_generate') return 'Run the matching HG002 caller command from `output/wgs-caller-manifest.json` to generate the query VCF.';
  if (missingInputs.length > 0) return `Provide local HG002 caller input(s): ${missingInputs.join(', ')}.`;
  return `Install or containerize the required caller tool(s): ${tools.join(' / ')} (${missingCallerRequirements.join(', ')}).`;
}

function installHint(tool: string): string {
  const normalized = tool.toLowerCase();
  if (normalized === 'bcftools' || normalized === 'bgzip' || normalized === 'tabix') return 'Install htslib/bcftools, for example with Homebrew or Bioconda.';
  if (normalized === 'truvari') return 'Install Truvari with pipx/pip or Bioconda, or run a pinned container.';
  if (normalized === 'hap.py') return 'Install hap.py through a GIAB/RTG/hap.py container or Bioconda environment.';
  if (normalized === 'gatk-sv') return 'Install Cromwell and set GATK_SV_WDL_DIR to a local GATK-SV WDL checkout; this is not satisfied by plain GATK alone.';
  if (normalized.includes('gatk')) return 'Install GATK locally or use the broadinstitute/gatk container image.';
  if (normalized === 'manta') return 'Install Manta locally or use the quay.io/biocontainers/manta image.';
  if (normalized === 'expansionhunter') return 'Install ExpansionHunter locally or use the quay.io/biocontainers/expansionhunter image.';
  if (normalized === 'ensembl vep') return 'Install Ensembl VEP with an offline cache or use the ensemblorg/ensembl-vep image.';
  return `Install ${tool} before running this plan.`;
}

function defaultContainerPlatform(_image: string): string {
  return 'linux/amd64';
}

function isRunnableContainerImage(image: string | undefined): image is string {
  return Boolean(image && !/\s/.test(image) && /[:/]/.test(image));
}

function containerFields(image: string | undefined): {
  container_image?: string;
  container_platform?: string;
  container_image_present?: boolean;
  container_image_status?: ContainerImageStatus;
  container_pull_command?: string;
} {
  if (!isRunnableContainerImage(image)) return {};
  const platform = defaultContainerPlatform(image);
  const status = dockerImageStatus(image);
  return {
    container_image: image,
    container_platform: platform,
    container_image_present: status === 'present',
    container_image_status: status,
    container_pull_command: `docker pull --platform ${platform} ${image}`,
  };
}

function benchmarkContainer(tool: string): { image: string; platform: string; commandPath: string } | undefined {
  if (tool === 'truvari') return { image: 'adamgiess/truvari:5.3.0', platform: 'linux/amd64', commandPath: 'truvari' };
  if (tool === 'hap.py') return { image: 'quay.io/biocontainers/hap.py:0.3.15--py27hcb73b3d_0', platform: 'linux/amd64', commandPath: 'hap.py' };
  return undefined;
}

function benchmarkToolCheck(tool: string): WgsQueryReadinessResult['run_plan']['required_tools'][number] {
  const container = benchmarkContainer(tool);
  const containerStatus = container ? dockerImageStatus(container.image) : undefined;
  return {
    tool,
    role: 'benchmark',
    available: tool === 'custom' || hasCommand(tool),
    install_hint: installHint(tool),
    container_image: container?.image,
    container_platform: container?.platform,
    container_image_present: container ? containerStatus === 'present' : undefined,
    container_image_status: containerStatus,
    container_pull_command: container ? `docker pull --platform ${container.platform} ${container.image}` : undefined,
  };
}

function callerToolCheck(caller: WgsQueryReadinessResult['required_callers'][number]): WgsQueryReadinessResult['run_plan']['required_tools'][number] {
  return {
    tool: caller.tool,
    role: 'caller',
    available: caller.available,
    install_hint: installHint(caller.tool),
    ...containerFields(caller.container_image),
  };
}

function postprocessToolChecks(): Array<{ tool: string; role: 'postprocess'; available: boolean; install_hint: string }> {
  return ['bcftools', 'bgzip', 'tabix'].map(tool => ({
    tool,
    role: 'postprocess',
    available: hasCommand(tool),
    install_hint: installHint(tool),
  }));
}

function shellQuote(value: string): string {
  return `'${value.replace(/'/g, `'\\''`)}'`;
}

function shellArg(value: string): string {
  return value.startsWith('${') && value.endsWith('}') ? `"${value}"` : shellQuote(value);
}

function commandWithOutput(command: string, truthset: ExternalTruthset, queryVcfPath: string, referencePath: string, rawInputPath: string): string {
  const workDir = path.dirname(queryVcfPath);
  const outputPrefix = queryVcfPath.replace(/\.vcf\.gz$/i, '');
  const replaced = command
    .replaceAll('<sample.bam|sample.cram>', shellQuote(rawInputPath))
    .replaceAll('<reference.fa>', shellQuote(referencePath));

  if (/gatk HaplotypeCaller/i.test(command)) {
    const gvcfPath = `${outputPrefix}.g.vcf.gz`;
    return `gatk HaplotypeCaller -R ${shellArg(referencePath)} -I ${shellArg(rawInputPath)} -O ${shellQuote(gvcfPath)} && gatk GenotypeGVCFs -R ${shellArg(referencePath)} -V ${shellQuote(gvcfPath)} -O ${shellQuote(queryVcfPath)}`;
  }
  if (/configManta\.py/i.test(command)) {
    const mantaDir = path.join(workDir, `${truthset.id}-manta`);
    return `configManta.py --bam ${shellArg(rawInputPath)} --referenceFasta ${shellArg(referencePath)} --runDir ${shellQuote(mantaDir)} && ${shellQuote(path.join(mantaDir, 'runWorkflow.py'))} && cp ${shellQuote(path.join(mantaDir, 'results/variants/diploidSV.vcf.gz'))} ${shellQuote(queryVcfPath)}`;
  }
  if (/ExpansionHunter/i.test(command)) {
    const catalog = shellArg('${WGS_REPEAT_CATALOG}');
    const prefix = shellQuote(outputPrefix);
    return `ExpansionHunter --reads ${shellArg(rawInputPath)} --reference ${shellArg(referencePath)} --variant-catalog ${catalog} --output-prefix ${prefix} && bgzip -c ${shellQuote(`${outputPrefix}.vcf`)} > ${shellQuote(queryVcfPath)}`;
  }
  if (/CollectReadCounts/i.test(command)) {
    const countsPath = `${outputPrefix}.counts.hdf5`;
    const intervals = shellArg('${WGS_READCOUNT_INTERVALS}');
    const modelDir = shellArg('${GATK_GCNV_MODEL_DIR}');
    const workDirQuoted = shellQuote(path.join(workDir, `${truthset.id}-gcnv`));
    return `gatk CollectReadCounts -I ${shellArg(rawInputPath)} -R ${shellArg(referencePath)} -L ${intervals} --interval-merging-rule OVERLAPPING_ONLY -O ${shellQuote(countsPath)} && gatk GermlineCNVCaller --run-mode CASE --contig-ploidy-calls ${modelDir} --model ${modelDir} --input ${shellQuote(countsPath)} --output ${workDirQuoted} --output-prefix ${shellQuote(truthset.id)} # then convert genotyped segments to ${shellQuote(queryVcfPath)}`;
  }
  if (/GATK-SV WDL/i.test(command)) {
    return `# Run GATK-SV WDL modules with Cromwell/Terra using ${shellArg(rawInputPath)} and ${shellArg(referencePath)}, then export the genotyped SV VCF to ${shellQuote(queryVcfPath)}`;
  }
  if (/vep/i.test(command)) {
    return `vep --cache --offline --everything --vcf -i ${shellQuote(queryVcfPath)} -o ${shellQuote(queryVcfPath.replace(/\.vcf\.gz$/i, '.vep.vcf'))}`;
  }
  return replaced;
}

function validationCommand(truthset: ExternalTruthset): string {
  return `npm run wgs:external-validation -- --run # scores ${truthset.id} once truth/query inputs, indexes, and benchmark tools are present`;
}

function containerValidationCommand(truthset: ExternalTruthset, truthsetPath: string, packageDir: string, queryVcfPath: string): string | undefined {
  const container = benchmarkContainer(truthset.benchmark_tool);
  if (!container) return undefined;
  const queryRelative = path.relative(packageDir, queryVcfPath);
  const commandPrefix = `docker run --rm --platform ${container.platform} -v "$(cd ../.. && pwd)":/work -w /work/skills/longevity-analysis ${container.image} ${container.commandPath}`;
  if (truthset.benchmark_tool === 'truvari') {
    const outputDir = (truthset.metrics_json ?? `output/external-validation/${truthset.id}-truvari-summary.json`).replace(/\.json$/i, '');
    return `${commandPrefix} bench -b ${shellQuote(path.relative(packageDir, resolveInputPath(truthset.truth_vcf, truthsetPath, packageDir)))} -c ${shellQuote(queryRelative)}${truthset.confident_regions ? ` --includebed ${shellQuote(path.relative(packageDir, resolveInputPath(truthset.confident_regions, truthsetPath, packageDir)))}` : ''} -o ${shellQuote(outputDir)}`;
  }
  if (truthset.benchmark_tool === 'hap.py') {
    const outPrefix = (truthset.metrics_json ?? `output/external-validation/${truthset.id}-happy-summary.json`).replace(/\.json$/i, '');
    return `${commandPrefix} ${shellQuote(path.relative(packageDir, resolveInputPath(truthset.truth_vcf, truthsetPath, packageDir)))} ${shellQuote(queryRelative)}${truthset.confident_regions ? ` -f ${shellQuote(path.relative(packageDir, resolveInputPath(truthset.confident_regions, truthsetPath, packageDir)))}` : ''} -o ${shellQuote(outPrefix)}`;
  }
  return undefined;
}

function runPlanFor(
  truthset: ExternalTruthset,
  truthsetPath: string,
  packageDir: string,
  queryVcfPath: string,
  queryVcfIndexPath: string,
  requiredCallers: WgsQueryReadinessResult['required_callers'],
  rawInput: string | undefined,
  reference: string | undefined,
): WgsQueryReadinessResult['run_plan'] {
  const rawInputPath = rawInput ?? '${HG002_BAM_OR_CRAM}';
  const referencePath = reference ?? '${HG002_REFERENCE_FASTA}';
  const callerCommands = requiredCallers
    .filter(caller => !/^Ensembl VEP$/i.test(caller.tool))
    .map(caller => commandWithOutput(caller.command_template, truthset, queryVcfPath, referencePath, rawInputPath));
  const annotationCommands = requiredCallers
    .filter(caller => /^Ensembl VEP$/i.test(caller.tool))
    .map(caller => commandWithOutput(caller.command_template, truthset, queryVcfPath, referencePath, rawInputPath));
  const callerToolChecks = requiredCallers.map(caller => callerToolCheck(caller));
  const requiredTools = [
    ...callerToolChecks,
    ...postprocessToolChecks(),
    benchmarkToolCheck(truthset.benchmark_tool),
  ];
  const containerCommand = containerValidationCommand(truthset, truthsetPath, packageDir, queryVcfPath);

  return {
    env: {
      HG002_BAM_OR_CRAM: rawInput ?? 'path/to/HG002.bam-or.cram',
      HG002_REFERENCE_FASTA: reference ?? 'path/to/reference.fa',
      WGS_REPEAT_CATALOG: truthset.variant_classes.includes('tandem_repeats') ? 'path/to/repeat-catalog.json' : '',
      WGS_READCOUNT_INTERVALS: truthset.variant_classes.includes('copy_number_variants') ? 'path/to/read-count-intervals.interval_list' : '',
      GATK_GCNV_MODEL_DIR: truthset.variant_classes.includes('copy_number_variants') ? 'path/to/gcnv-model-dir' : '',
      GATK_SV_WDL_DIR: truthset.variant_classes.some(item => ['copy_number_variants', 'large_indels', 'rearrangements'].includes(item)) ? 'path/to/gatk-sv/wdl' : '',
    },
    required_tools: requiredTools,
    setup_commands: [
      `mkdir -p ${shellQuote(path.dirname(queryVcfPath))}`,
      'Install required tools where `run_plan.required_tools[].available` is false before running the caller commands.',
    ],
    caller_commands: callerCommands.length > 0 ? callerCommands : ['No raw caller command is configured for this truthset yet.'],
    postprocess_commands: [
      ...annotationCommands,
      `bcftools sort -Oz -o ${shellQuote(queryVcfPath.replace(/\.vcf\.gz$/i, '.sorted.tmp.vcf.gz'))} ${shellQuote(queryVcfPath)} && mv ${shellQuote(queryVcfPath.replace(/\.vcf\.gz$/i, '.sorted.tmp.vcf.gz'))} ${shellQuote(queryVcfPath)}`,
      `bcftools index -t ${shellQuote(queryVcfPath)}`,
    ],
    validation_command: validationCommand(truthset),
    ...(containerCommand ? { container_validation_command: containerCommand } : {}),
    expected_outputs: [queryVcfPath, queryVcfIndexPath],
  };
}

function buildSetupPlan(results: WgsQueryReadinessResult[]): WgsQueryReadinessReport['setup_plan'] {
  const requiredTools = uniqueToolChecks(results.flatMap(result => result.run_plan.required_tools));
  const callerContainerPullCommands = unique(requiredTools
    .filter(tool => tool.role === 'caller' && tool.container_pull_command && !tool.container_image_present)
    .map(tool => tool.container_pull_command ?? ''));
  const benchmarkContainerPullCommands = unique(requiredTools
    .filter(tool => tool.role === 'benchmark' && tool.container_pull_command && !tool.container_image_present)
    .map(tool => tool.container_pull_command ?? ''));
  const nativeToolInstallHints = unique(requiredTools
    .filter(tool => !tool.available && !tool.container_image)
    .map(tool => `${tool.tool}: ${tool.install_hint}`));
  const env = results.reduce<Record<string, string>>((acc, result) => {
    for (const [key, value] of Object.entries(result.run_plan.env)) {
      if (value) acc[key] = value;
    }
    return acc;
  }, {});
  const setupCommands = unique(results.flatMap(result => result.run_plan.setup_commands));
  const queryGenerationCommands = unique(results.flatMap(result => result.run_plan.caller_commands));
  const postprocessCommands = unique(results.flatMap(result => result.run_plan.postprocess_commands));
  const validationCommands = unique(results.flatMap(result => [
    result.run_plan.validation_command,
    result.run_plan.container_validation_command ?? '',
  ]));
  const missingInputs = unique(results.flatMap(result => result.missing_inputs));

  return {
    missing_inputs: missingInputs,
    env,
    caller_container_pull_commands: callerContainerPullCommands,
    benchmark_container_pull_commands: benchmarkContainerPullCommands,
    native_tool_install_hints: nativeToolInstallHints,
    setup_commands: setupCommands,
    query_generation_commands: queryGenerationCommands,
    postprocess_commands: postprocessCommands,
    validation_commands: validationCommands,
    next_commands: unique([
      ...setupCommands,
      ...callerContainerPullCommands,
      ...benchmarkContainerPullCommands,
      ...queryGenerationCommands,
      ...postprocessCommands,
      ...validationCommands,
    ]),
  };
}

function buildLocalRunAssessment(
  results: WgsQueryReadinessResult[],
  setupPlan: WgsQueryReadinessReport['setup_plan'],
): WgsQueryReadinessReport['local_run_assessment'] {
  const hardSteps = results.filter(result => result.local_difficulty === 'hard').length;
  const runnableNow = results.length > 0 && results.every(result => result.status === 'ready_to_validate' || result.status === 'ready_to_generate');
  const hasMissingInputs = setupPlan.missing_inputs.length > 0;
  const hasMissingContainers = setupPlan.caller_container_pull_commands.length + setupPlan.benchmark_container_pull_commands.length > 0;
  const hasNativeOnlyTools = setupPlan.native_tool_install_hints.length > 0;
  const blockers = unique([
    ...setupPlan.missing_inputs.map(input => `missing input: ${input}`),
    ...(hasMissingContainers ? [`missing container images: ${setupPlan.caller_container_pull_commands.length + setupPlan.benchmark_container_pull_commands.length}`] : []),
    ...setupPlan.native_tool_install_hints.map(hint => `native setup: ${hint}`),
  ]);
  const difficulty: 'easy' | 'medium' | 'hard' = runnableNow
    ? 'medium'
    : hardSteps > 0 || hasMissingInputs || hasNativeOnlyTools
      ? 'hard'
      : 'medium';

  return {
    difficulty,
    runnable_now: runnableNow,
    local_only_possible: true,
    estimated_active_setup_hours: difficulty === 'hard' ? { min: 4, max: 12 } : { min: 1, max: 3 },
    estimated_wall_clock_hours: difficulty === 'hard' ? { min: 24, max: 96 } : { min: 4, max: 24 },
    recommended_environment: 'Docker-capable linux/amd64 environment or equivalent, 16+ CPU threads, 64GB+ RAM, and 500GB+ free disk for HG002 BAM/CRAM, reference, caller intermediates, and benchmark outputs.',
    blocker_count: blockers.length,
    blockers,
  };
}

function scriptLineList(items: string[]): string {
  return items.length > 0 ? items.map(item => `  - ${item}`).join('\n') : '  - none';
}

function scriptCommandBlock(title: string, commands: string[]): string {
  return [
    `# ${title}`,
    ...(commands.length > 0 ? commands.map(command => command) : ['# none']),
  ].join('\n');
}

export function renderWgsLocalSetupScript(report: WgsQueryReadinessReport): string {
  const envKeys = Object.keys(report.setup_plan.env);
  const inputChecks = envKeys.map(key => [
    `if [[ -z "\${${key}:-}" || ! -e "\${${key}}" ]]; then`,
    `  echo "missing ${key}: set it to an existing local path" >&2`,
    '  missing=1',
    'fi',
  ].join('\n')).join('\n');
  const callerPulls = report.setup_plan.caller_container_pull_commands.join('\n') || 'echo "No caller container pulls needed."';
  const benchmarkPulls = report.setup_plan.benchmark_container_pull_commands.join('\n') || 'echo "No benchmark container pulls needed."';
  const setupSummary = [
    `Difficulty: ${report.local_run_assessment.difficulty}`,
    `Runnable now: ${report.local_run_assessment.runnable_now}`,
    `Active setup hours: ${report.local_run_assessment.estimated_active_setup_hours.min}-${report.local_run_assessment.estimated_active_setup_hours.max}`,
    `Wall-clock hours: ${report.local_run_assessment.estimated_wall_clock_hours.min}-${report.local_run_assessment.estimated_wall_clock_hours.max}`,
    `Recommended environment: ${report.local_run_assessment.recommended_environment}`,
    '',
    'Missing inputs:',
    scriptLineList(report.setup_plan.missing_inputs),
    '',
    'Native setup hints:',
    scriptLineList(report.setup_plan.native_tool_install_hints),
    '',
    'Environment variables expected by check-inputs:',
    scriptLineList(envKeys),
  ].join('\n');
  const planText = [
    scriptCommandBlock('Setup commands', report.setup_plan.setup_commands),
    '',
    scriptCommandBlock('Caller container pulls', report.setup_plan.caller_container_pull_commands),
    '',
    scriptCommandBlock('Benchmark container pulls', report.setup_plan.benchmark_container_pull_commands),
    '',
    scriptCommandBlock('Query generation commands', report.setup_plan.query_generation_commands),
    '',
    scriptCommandBlock('Postprocess commands', report.setup_plan.postprocess_commands),
    '',
    scriptCommandBlock('Validation commands', report.setup_plan.validation_commands),
  ].join('\n');

  return `#!/usr/bin/env bash
set -euo pipefail

# Generated by npm run wgs:query-readiness.
# Usage:
#   ./output/wgs-local-setup-plan.sh summary
#   ./output/wgs-local-setup-plan.sh check-inputs
#   ./output/wgs-local-setup-plan.sh pull-containers
#   ./output/wgs-local-setup-plan.sh print-plan

phase="\${1:-summary}"

case "$phase" in
  summary)
    cat <<'SUMMARY'
${setupSummary}
SUMMARY
    ;;
  check-inputs)
    missing=0
${inputChecks || '    echo "No input path checks configured."'}
    if [[ "$missing" -ne 0 ]]; then
      exit 1
    fi
    echo "All configured WGS input paths exist."
    ;;
  pull-containers)
${callerPulls}
${benchmarkPulls}
    ;;
  print-plan)
    cat <<'PLAN'
${planText}
PLAN
    ;;
  *)
    echo "Unknown phase: $phase" >&2
    echo "Expected one of: summary, check-inputs, pull-containers, print-plan" >&2
    exit 2
    ;;
esac
`;
}

export function buildWgsQueryReadinessReport(
  config: TruthsetConfig,
  truthsetPath: string,
  packageDir: string,
  inputPath?: string,
  referencePath?: string,
): WgsQueryReadinessReport {
  const configuredInput = inputPath ?? envPath('HG002_BAM', 'HG002_CRAM', 'WGS_BAM', 'WGS_CRAM');
  const configuredReference = referencePath ?? envPath('HG002_REFERENCE_FASTA', 'REFERENCE_FASTA', 'WGS_REFERENCE_FASTA');
  const rawInput = existingPath(configuredInput);
  const reference = existingPath(configuredReference);
  const manifest = buildWgsCallerManifest(rawInput ?? '<sample.bam|sample.cram>', reference ?? '<reference.fa>');

  const results = (config.external_truthsets ?? []).map(truthset => {
    const queryVcfPath = resolveInputPath(truthset.query_vcf, truthsetPath, packageDir);
    const queryVcfIndexPath = resolveInputPath(truthset.query_vcf_index ?? `${truthset.query_vcf}.tbi`, truthsetPath, packageDir);
    const queryVcfPresent = fs.existsSync(queryVcfPath);
    const queryVcfIndexPresent = fs.existsSync(queryVcfIndexPath);
    const requiredCallers = manifest.caller_steps
      .filter(step => matchesTruthset(step, truthset))
      .map(step => ({
        id: step.id,
        tool: step.tool,
        available: step.available,
        command_template: step.command_template,
        missing_requirements: step.missing_requirements,
        ...containerFields(step.container_image),
      }));
    const callerAvailable = requiredCallers.some(caller => caller.available);
    const missingCallerRequirements = unique(requiredCallers.flatMap(caller => caller.missing_requirements));
    const missingInputs = unique([
      rawInput ? '' : 'HG002 BAM/CRAM',
      reference ? '' : 'matching reference FASTA',
      ...missingDomainInputs(truthset),
    ]);
    const readyToGenerate = !queryVcfPresent && callerAvailable && missingInputs.length === 0;
    const status = statusFor({
      queryVcfPresent,
      queryVcfIndexPresent,
      readyToGenerate,
      missingInputs,
      missingCallerRequirements,
    });
    const callerTools = unique(requiredCallers.map(caller => caller.tool));

    return {
      truthset_id: truthset.id,
      source_name: truthset.source_name,
      benchmark_tool: truthset.benchmark_tool,
      genome_build: truthset.genome_build,
      variant_classes: truthset.variant_classes,
      query_vcf_path: queryVcfPath,
      query_vcf_index_path: queryVcfIndexPath,
      query_vcf_present: queryVcfPresent,
      query_vcf_index_present: queryVcfIndexPresent,
      required_callers: requiredCallers,
      caller_available: callerAvailable,
      caller_tools: callerTools,
      missing_caller_requirements: missingCallerRequirements,
      raw_input_path: rawInput,
      reference_path: reference,
      missing_inputs: missingInputs,
      ready_to_generate: readyToGenerate,
      status,
      local_difficulty: difficultyFor(status),
      run_plan: runPlanFor(truthset, truthsetPath, packageDir, queryVcfPath, queryVcfIndexPath, requiredCallers, rawInput, reference),
      next_action: nextActionFor(status, missingInputs, missingCallerRequirements, callerTools),
    };
  });

  const requiredTools = uniqueToolChecks(results.flatMap(result => result.run_plan.required_tools));
  const callerTools = requiredTools.filter(tool => tool.role === 'caller');
  const callerContainerTools = callerTools.filter(tool => tool.container_image);
  const postprocessTools = requiredTools.filter(tool => tool.role === 'postprocess');
  const benchmarkTools = requiredTools.filter(tool => tool.role === 'benchmark');
  const benchmarkContainerTools = benchmarkTools.filter(tool => tool.container_image);
  const setupPlan = buildSetupPlan(results);
  const localRunAssessment = buildLocalRunAssessment(results, setupPlan);
  const summary = {
    truthsets: results.length,
    ready_to_validate: results.filter(result => result.status === 'ready_to_validate').length,
    ready_to_generate: results.filter(result => result.ready_to_generate).length,
    query_vcfs_present: results.filter(result => result.query_vcf_present).length,
    query_indexes_present: results.filter(result => result.query_vcf_index_present).length,
    missing_inputs: results.filter(result => result.missing_inputs.length > 0).length,
    missing_caller_tools: results.filter(result => !result.caller_available).length,
    caller_container_plans: callerContainerTools.length,
    caller_container_images_present: callerContainerTools.filter(tool => tool.container_image_present).length,
    caller_container_image_timeouts: callerContainerTools.filter(tool => tool.container_image_status === 'timeout').length,
    postprocess_tools_available: postprocessTools.filter(tool => tool.available).length,
    postprocess_tools_required: postprocessTools.length,
    benchmark_tools_available: benchmarkTools.filter(tool => tool.available).length,
    benchmark_tools_required: benchmarkTools.length,
    benchmark_container_plans: benchmarkContainerTools.length,
    benchmark_container_images_present: benchmarkContainerTools.filter(tool => tool.container_image_present).length,
    benchmark_container_image_timeouts: benchmarkContainerTools.filter(tool => tool.container_image_status === 'timeout').length,
    container_runtime_available: hasCommand('docker'),
    hard_local_steps: results.filter(result => result.local_difficulty === 'hard').length,
    run_plans: results.filter(result => result.run_plan.caller_commands.length > 0 && result.run_plan.expected_outputs.length >= 2).length,
    setup_plan_steps: setupPlan.next_commands.length,
  };

  return {
    generated_at: new Date().toISOString(),
    truthset_path: truthsetPath,
    input_path: configuredInput,
    reference_path: configuredReference,
    local_run_assessment: localRunAssessment,
    results,
    setup_plan: setupPlan,
    summary,
    next_actions: results.filter(result => result.status !== 'ready_to_validate').map(result => `${result.truthset_id}: ${result.next_action}`),
    ready_for_query_generation: summary.truthsets > 0 && summary.ready_to_generate + summary.ready_to_validate >= summary.truthsets,
  };
}

function main(): void {
  const scriptDir = path.dirname(fileURLToPath(import.meta.url));
  const packageDir = path.resolve(scriptDir, '../..');
  const truthsetPath = path.resolve(argValue('--truthsets') ?? path.join(packageDir, 'references/wgs-validation-truthsets.json'));
  const outPath = path.resolve(argValue('--out') ?? path.join(packageDir, 'output/wgs-query-readiness.json'));
  const setupScriptPath = path.resolve(argValue('--setup-script') ?? path.join(packageDir, 'output/wgs-local-setup-plan.sh'));
  const report = buildWgsQueryReadinessReport(
    readJson<TruthsetConfig>(truthsetPath),
    truthsetPath,
    packageDir,
    argValue('--input'),
    argValue('--reference'),
  );
  report.setup_script_path = setupScriptPath;

  fs.mkdirSync(path.dirname(outPath), { recursive: true });
  fs.writeFileSync(outPath, `${JSON.stringify(report, null, 2)}\n`, 'utf8');
  fs.mkdirSync(path.dirname(setupScriptPath), { recursive: true });
  fs.writeFileSync(setupScriptPath, renderWgsLocalSetupScript(report), 'utf8');
  fs.chmodSync(setupScriptPath, 0o755);
  console.log(JSON.stringify({
    status: report.ready_for_query_generation ? 'ready' : 'setup_required',
    output: outPath,
    setup_script: setupScriptPath,
    summary: report.summary,
    local_run_assessment: report.local_run_assessment,
    next_actions: report.next_actions.slice(0, 8),
  }, null, 2));
  if (process.argv.includes('--strict') && !report.ready_for_query_generation) process.exit(1);
}

if (process.argv[1]?.endsWith('wgs_query_readiness.ts')) {
  main();
}
